    87→export function setupRateLimitMiddleware(app: Express): void {
    88→  app.use((req: Request, res: Response, next: NextFunction) => {
    89→    const clientIp = getClientIp(req)
    90→    const rateLimit = checkRateLimit(clientIp)
    91→
    92→    if (!rateLimit.allowed) {
    93→      return res.status(429).json({
    94→        error: 'Too many failed attempts. Please try again later.',
    95→        retryAfter: rateLimit.retryAfter
    96→      }).setHeader('Retry-After', String(rateLimit.retryAfter || 900))
    97→    }
    98→
    99→    next()
   100→  })
   101→}
