import { useCallback, useEffect, useRef, useState } from 'react'
import { tasksCache, beadsStatusCache } from '../../utils/lruCache.js'
import type { UnifiedTask, TaskAdapter, BackendKind, AutomationEligibility, CreateTaskParams } from './adapters/types.js'
import { detectBackend, getAdapter } from './adapters/detect.js'
import type { BeadsState } from './useBeadsState.js'

export interface TaskCrudCallbacks {
  loadTasks: (showLoading?: boolean) => Promise<void>
  handleInitBeads: () => Promise<void>
  handleInitKspec: () => Promise<void>
  handleUpgradeToKspec: () => Promise<void>
  handleInstallPython: () => Promise<void>
  handleInstallBeads: () => Promise<void>
  handleCreateTask: () => Promise<void>
  handleCompleteTask: (taskId: string) => Promise<void>
  handleDeleteTask: (taskId: string) => Promise<void>
  handleCycleStatus: (taskId: string, currentStatus: string) => Promise<void>
  handleSaveEdit: () => Promise<void>
  handleCancelEdit: () => void
  handleClearCompleted: () => Promise<void>
  upgrading: boolean
}

export interface TaskCrudState {
  showCreateModal: boolean
  setShowCreateModal: React.Dispatch<React.SetStateAction<boolean>>
  newTaskTitle: string
  setNewTaskTitle: React.Dispatch<React.SetStateAction<string>>
  newTaskType: string
  setNewTaskType: React.Dispatch<React.SetStateAction<string>>
  newTaskPriority: number
  setNewTaskPriority: React.Dispatch<React.SetStateAction<number>>
  newTaskDescription: string
  setNewTaskDescription: React.Dispatch<React.SetStateAction<string>>
  newTaskLabels: string
  setNewTaskLabels: React.Dispatch<React.SetStateAction<string>>
  newTaskAutomation: AutomationEligibility | ''
  setNewTaskAutomation: React.Dispatch<React.SetStateAction<AutomationEligibility | ''>>
  editingTaskId: string | null
  setEditingTaskId: React.Dispatch<React.SetStateAction<string | null>>
  editingTitle: string
  setEditingTitle: React.Dispatch<React.SetStateAction<string>>
  editInputRef: React.RefObject<HTMLInputElement>
}

interface UseBeadsTasksParams {
  projectPath: string | null
  beadsState: BeadsState
  setBeadsState: React.Dispatch<React.SetStateAction<BeadsState>>
  tasks: UnifiedTask[]
  setTasks: React.Dispatch<React.SetStateAction<UnifiedTask[]>>
  currentProjectRef: React.MutableRefObject<string | null>
  suppressWatcherReloadRef: React.MutableRefObject<boolean>
  setError: (error: string) => void
  adapter: TaskAdapter | null
  backendKind: BackendKind
}

export function useBeadsTasks({
  projectPath,
  beadsState,
  setBeadsState,
  tasks,
  setTasks,
  currentProjectRef,
  suppressWatcherReloadRef,
  setError,
  adapter,
  backendKind
}: UseBeadsTasksParams): TaskCrudCallbacks & TaskCrudState {
  const [showCreateModal, setShowCreateModal] = useState(false)
  const [newTaskTitle, setNewTaskTitle] = useState('')
  const [newTaskType, setNewTaskType] = useState<string>('task')
  const [newTaskPriority, setNewTaskPriority] = useState<number>(2)
  const [newTaskDescription, setNewTaskDescription] = useState('')
  const [newTaskLabels, setNewTaskLabels] = useState('')
  const [newTaskAutomation, setNewTaskAutomation] = useState<AutomationEligibility | ''>('')
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null)
  const [editingTitle, setEditingTitle] = useState('')
  const editInputRef = useRef<HTMLInputElement>(null)
  const [upgrading, setUpgrading] = useState(false)

  const loadTasks = useCallback(async (showLoading = true) => {
    if (!projectPath) return

    const loadingForProject = projectPath

    if (showLoading) setBeadsState({ status: 'loading' })

    try {
      // Detect backend if we don't have an adapter yet
      const kind = backendKind !== 'none' ? backendKind : await detectBackend(loadingForProject)
      const currentAdapter = kind !== 'none' ? getAdapter(kind) : null

      if (currentProjectRef.current !== loadingForProject) return

      if (!currentAdapter) {
        // Check if beads is at least installable
        const beadsStatus = await window.electronAPI?.beadsCheck(loadingForProject)
        if (currentProjectRef.current !== loadingForProject) return

        if (!beadsStatus?.installed) {
          setBeadsState({ status: 'not_installed', installing: null, needsPython: false, installError: null, installStatus: null })
          return
        }

        // Neither backend initialized — offer choice
        setBeadsState({ status: 'not_initialized', initializing: false, availableBackends: ['beads', 'kspec'] })
        return
      }

      // Backend found — check status
      const status = await currentAdapter.check(loadingForProject)
      if (currentProjectRef.current !== loadingForProject) return

      beadsStatusCache.set(loadingForProject, status)

      if (!status.initialized) {
        setBeadsState({ status: 'not_initialized', initializing: false, availableBackends: [kind] })
        return
      }

      // Load tasks via adapter
      const taskList = await currentAdapter.list(loadingForProject)
      if (currentProjectRef.current !== loadingForProject) return

      setTasks(taskList)
      tasksCache.set(loadingForProject, taskList)
      setBeadsState({ status: 'ready' })
    } catch (e) {
      if (currentProjectRef.current === loadingForProject) {
        setBeadsState({ status: 'error', error: String(e) })
      }
    }
  }, [projectPath, setBeadsState, setTasks, currentProjectRef, backendKind])

  const handleInitBeads = async (): Promise<void> => {
    if (!projectPath) return
    if (beadsState.status !== 'not_initialized') return

    setBeadsState({ status: 'not_initialized', initializing: true, availableBackends: ['beads'] })

    try {
      const result = await window.electronAPI?.beadsInit(projectPath)
      if (result?.success) {
        loadTasks()
      } else {
        setBeadsState({ status: 'error', error: result?.error || 'Failed to initialize beads' })
      }
    } catch (e) {
      setBeadsState({ status: 'error', error: String(e) })
    }
  }

  const handleInitKspec = async (): Promise<void> => {
    if (!projectPath) return
    if (beadsState.status !== 'not_initialized') return

    setBeadsState({ status: 'not_initialized', initializing: true, availableBackends: ['kspec'] })

    try {
      const result = await window.electronAPI?.kspecInit?.(projectPath)
      if (result?.success) {
        // Ensure daemon is running
        await window.electronAPI?.kspecEnsureDaemon?.(projectPath)
        loadTasks()
      } else {
        setBeadsState({ status: 'error', error: result?.error || 'Failed to initialize kspec' })
      }
    } catch (e) {
      setBeadsState({ status: 'error', error: String(e) })
    }
  }

  const handleUpgradeToKspec = async (): Promise<void> => {
    if (!projectPath) return
    setUpgrading(true)

    try {
      // Check if kspec CLI is installed, install if not
      const cliCheck = await window.electronAPI?.kspecCheckCli?.()
      if (!cliCheck?.installed) {
        const installResult = await window.electronAPI?.kspecInstallCli?.()
        if (!installResult?.success) {
          setError(installResult?.error || 'Failed to install kspec CLI')
          setUpgrading(false)
          return
        }
      }

      // Run migration: reads beads tasks, inits kspec, creates tasks, removes .beads/
      const result = await window.electronAPI?.kspecMigrateFromBeads?.(projectPath)
      if (!result?.success) {
        setError(result?.error || 'Migration failed')
        setUpgrading(false)
        return
      }

      // Ensure daemon is running
      await window.electronAPI?.kspecEnsureDaemon?.(projectPath)

      // Clear caches and reload — backend has changed from beads to kspec
      tasksCache.delete(projectPath)
      beadsStatusCache.delete(projectPath)
      loadTasks()
    } catch (e) {
      setError(String(e))
    } finally {
      setUpgrading(false)
    }
  }

  const handleInstallBeads = async (): Promise<void> => {
    setBeadsState({ status: 'not_installed', installing: 'beads', needsPython: false, installError: null, installStatus: null })

    try {
      const result = await window.electronAPI?.beadsInstall()
      if (result?.success) {
        loadTasks()
      } else if (result?.needsPython) {
        setBeadsState({ status: 'not_installed', installing: null, needsPython: true, installError: result.error || 'Python is required', installStatus: null })
      } else {
        setBeadsState({ status: 'not_installed', installing: null, needsPython: false, installError: result?.error || 'Installation failed', installStatus: null })
      }
    } catch (e) {
      setBeadsState({ status: 'not_installed', installing: null, needsPython: false, installError: String(e), installStatus: null })
    }
  }

  const handleInstallPython = async (): Promise<void> => {
    if (beadsState.status !== 'not_installed') return

    setBeadsState({ status: 'not_installed', installing: 'python', needsPython: true, installError: null, installStatus: 'Downloading Python...' })

    try {
      const result = await window.electronAPI?.pythonInstall()
      if (result?.success) {
        setBeadsState({ status: 'not_installed', installing: null, needsPython: false, installError: null, installStatus: null })
        handleInstallBeads()
      } else {
        setBeadsState({ status: 'not_installed', installing: null, needsPython: true, installError: result?.error || 'Python installation failed', installStatus: null })
      }
    } catch (e) {
      setBeadsState({ status: 'not_installed', installing: null, needsPython: true, installError: String(e), installStatus: null })
    }
  }

  const handleCreateTask = async (): Promise<void> => {
    if (!projectPath || !newTaskTitle.trim() || !adapter) return

    try {
      const result = await adapter.create(projectPath, {
        title: newTaskTitle.trim(),
        description: newTaskDescription.trim() || undefined,
        priority: newTaskPriority,
        type: newTaskType as CreateTaskParams['type'],
        tags: newTaskLabels.trim() || undefined,
        automation: newTaskAutomation || undefined
      })
      if (result.success) {
        setNewTaskTitle('')
        setNewTaskType('task')
        setNewTaskPriority(backendKind === 'kspec' ? 3 : 2)
        setNewTaskDescription('')
        setNewTaskLabels('')
        setNewTaskAutomation('')
        setShowCreateModal(false)
        loadTasks()
      } else {
        setError(result.error || 'Failed to create task')
      }
    } catch (e) {
      setError(String(e))
    }
  }

  const handleCompleteTask = async (taskId: string): Promise<void> => {
    if (!projectPath || !adapter) return

    const previousTasks = [...tasks]
    const updatedTasks = tasks.map(t => t.id === taskId ? { ...t, status: 'closed' as const } : t)
    setTasks(updatedTasks)
    tasksCache.set(projectPath, updatedTasks)

    try {
      const result = await adapter.complete(projectPath, taskId)
      if (!result.success) {
        setTasks(previousTasks)
        tasksCache.set(projectPath, previousTasks)
        setError(result.error || 'Failed to complete task')
      }
    } catch (e) {
      setTasks(previousTasks)
      tasksCache.set(projectPath, previousTasks)
      setError(String(e))
    }
  }

  const handleDeleteTask = async (taskId: string): Promise<void> => {
    if (!projectPath || !adapter) return

    const previousTasks = [...tasks]
    const updatedTasks = tasks.filter(t => t.id !== taskId)
    setTasks(updatedTasks)
    tasksCache.set(projectPath, updatedTasks)

    try {
      const result = await adapter.delete(projectPath, taskId)
      if (!result.success) {
        setTasks(previousTasks)
        tasksCache.set(projectPath, previousTasks)
        setError(result.error || 'Failed to delete task')
      }
    } catch (e) {
      setTasks(previousTasks)
      tasksCache.set(projectPath, previousTasks)
      setError(String(e))
    }
  }

  const handleCycleStatus = async (taskId: string, currentStatus: string): Promise<void> => {
    if (!projectPath || !adapter) return

    let nextStatus: string
    switch (currentStatus) {
      case 'open': nextStatus = 'in_progress'; break
      case 'in_progress': nextStatus = 'closed'; break
      default: nextStatus = 'open'
    }

    const previousTasks = [...tasks]
    const updatedTasks = tasks.map(t => t.id === taskId ? { ...t, status: nextStatus as UnifiedTask['status'] } : t)
    setTasks(updatedTasks)
    tasksCache.set(projectPath, updatedTasks)

    try {
      // Use adapter.cycleStatus() which knows the correct lifecycle endpoints
      // (e.g., kspec uses /start and /complete instead of generic PATCH)
      const result = await adapter.cycleStatus(projectPath, taskId, currentStatus as UnifiedTask['status'])
      if (!result.success) {
        setTasks(previousTasks)
        tasksCache.set(projectPath, previousTasks)
        setError(result.error || 'Failed to update task status')
      }
    } catch (e) {
      setTasks(previousTasks)
      tasksCache.set(projectPath, previousTasks)
      setError(String(e))
    }
  }

  const handleSaveEdit = async (): Promise<void> => {
    if (!projectPath || !editingTaskId || !editingTitle.trim() || !adapter) {
      setEditingTaskId(null)
      return
    }

    const originalTask = tasks.find(t => t.id === editingTaskId)
    if (originalTask && originalTask.title === editingTitle.trim()) {
      setEditingTaskId(null)
      return
    }

    try {
      const result = await adapter.update(projectPath, editingTaskId, { title: editingTitle.trim() })
      if (result.success) {
        loadTasks()
      } else {
        setError(result.error || 'Failed to update task title')
      }
    } catch (e) {
      setError(String(e))
    } finally {
      setEditingTaskId(null)
    }
  }

  const handleCancelEdit = (): void => {
    setEditingTaskId(null)
    setEditingTitle('')
  }

  const handleClearCompleted = async (): Promise<void> => {
    if (!projectPath || !adapter) return

    const closedTasks = tasks.filter(t => t.status === 'closed')
    if (closedTasks.length === 0) return

    const updatedTasks = tasks.filter(t => t.status !== 'closed')
    setTasks(updatedTasks)
    tasksCache.set(projectPath, updatedTasks)

    suppressWatcherReloadRef.current = true

    try {
      await Promise.allSettled(
        closedTasks.map(task => adapter.delete(projectPath, task.id))
      )
    } finally {
      suppressWatcherReloadRef.current = false
    }
  }

  // Set up watcher via adapter
  useEffect(() => {
    const isReady = beadsState.status === 'ready'
    if (!projectPath || !isReady || !adapter) return

    adapter.watch(projectPath)

    const cleanup = adapter.onTasksChanged((data: { cwd: string }) => {
      if (data.cwd === projectPath && !suppressWatcherReloadRef.current) {
        loadTasks(false)
      }
    })

    return () => {
      adapter.unwatch(projectPath)
      cleanup()
    }
  }, [projectPath, beadsState.status, loadTasks, suppressWatcherReloadRef, adapter])

  // Load tasks on mount and when project changes
  useEffect(() => {
    if (projectPath) {
      loadTasks(false)
    }
  }, [projectPath, loadTasks])

  return {
    loadTasks,
    handleInitBeads,
    handleInitKspec,
    handleUpgradeToKspec,
    handleInstallPython,
    handleInstallBeads,
    handleCreateTask,
    handleCompleteTask,
    handleDeleteTask,
    handleCycleStatus,
    handleSaveEdit,
    handleCancelEdit,
    handleClearCompleted,
    showCreateModal,
    setShowCreateModal,
    newTaskTitle,
    setNewTaskTitle,
    newTaskType,
    setNewTaskType,
    newTaskPriority,
    setNewTaskPriority,
    newTaskDescription,
    setNewTaskDescription,
    newTaskLabels,
    setNewTaskLabels,
    newTaskAutomation,
    setNewTaskAutomation,
    editingTaskId,
    setEditingTaskId,
    editingTitle,
    setEditingTitle,
    editInputRef,
    upgrading
  }
}

/**
 * PTY Routes - /api/pty/* endpoints
 */

import { Express, Request, Response } from 'express'
import { WebSocket } from 'ws'
import { validateProjectPath } from '../../mobile-security'
import { log } from '../utils'
import { LocalPty } from '../types'

export function setupPtyRoutes(
  app: Express,
  getPtyManager: () => any,
  getLocalPtys: () => Map<string, LocalPty>,
  getPtyStreams: () => Map<string, Set<WebSocket>>,
  getPtyDataBuffer: () => Map<string, string[]>,
  broadcastPtyData: (ptyId: string, data: string) => void,
  broadcastPtyExit: (ptyId: string, code: number) => void
): void {
  // Spawn a new PTY
  app.post('/api/pty/spawn', async (req: Request, res: Response) => {
    try {
      const { projectPath, sessionId, model, backend } = req.body

      if (!projectPath || typeof projectPath !== 'string') {
        return res.status(400).json({ error: 'projectPath is required' })
      }

      const pathValidation = validateProjectPath(projectPath)
      if (!pathValidation.valid) {
        return res.status(400).json({ error: pathValidation.error })
      }
      const safeProjectPath = pathValidation.normalizedPath!

      const ptyManager = getPtyManager()
      if (!ptyManager) {
        return res.status(500).json({ error: 'PTY manager not available' })
      }

      log('PTY spawn request', { projectPath: safeProjectPath, sessionId, model, backend })

      const ptyId = ptyManager.spawn(
        safeProjectPath,
        sessionId,
        undefined, // autoAcceptTools
        undefined, // permissionMode
        model,
        backend
      )

      // Track this PTY for cleanup
      const localPty: LocalPty = {
        ptyId,
        projectPath: safeProjectPath,
        dataCallbacks: new Set(),
        exitCallbacks: new Set()
      }
      getLocalPtys().set(ptyId, localPty)

      // Set up data forwarding to WebSocket streams
      ptyManager.onData(ptyId, (data: string) => {
        broadcastPtyData(ptyId, data)
      })

      // Set up exit handler
      ptyManager.onExit(ptyId, (code: number) => {
        log('PTY exited', { ptyId, code })
        broadcastPtyExit(ptyId, code)
        getLocalPtys().delete(ptyId)
        getPtyStreams().delete(ptyId)
        getPtyDataBuffer().delete(ptyId)
      })

      log('PTY spawned', { ptyId, projectPath })
      res.json({ ptyId })
    } catch (error) {
      log('PTY spawn error', { error: String(error) })
      res.status(500).json({ error: String(error) })
    }
  })

  // Write data to PTY
  app.post('/api/pty/:id/write', (req: Request, res: Response) => {
    try {
      const { id } = req.params
      const { data } = req.body

      if (!data || typeof data !== 'string') {
        return res.status(400).json({ error: 'data is required and must be a string' })
      }

      const ptyManager = getPtyManager()
      if (!ptyManager) {
        return res.status(500).json({ error: 'PTY manager not available' })
      }

      if (!ptyManager.getProcess(id)) {
        return res.status(404).json({ error: 'PTY not found' })
      }

      ptyManager.write(id, data)
      log('PTY write', { ptyId: id, dataLength: data.length })
      res.json({ success: true })
    } catch (error) {
      log('PTY write error', { error: String(error) })
      res.status(500).json({ error: String(error) })
    }
  })

  // Resize PTY
  app.post('/api/pty/:id/resize', (req: Request, res: Response) => {
    try {
      const { id } = req.params
      const { cols, rows } = req.body

      if (typeof cols !== 'number' || typeof rows !== 'number') {
        return res.status(400).json({ error: 'cols and rows are required and must be numbers' })
      }

      if (cols < 1 || rows < 1 || cols > 500 || rows > 500) {
        return res.status(400).json({ error: 'cols and rows must be between 1 and 500' })
      }

      const ptyManager = getPtyManager()
      if (!ptyManager) {
        return res.status(500).json({ error: 'PTY manager not available' })
      }

      if (!ptyManager.getProcess(id)) {
        return res.status(404).json({ error: 'PTY not found' })
      }

      ptyManager.resize(id, cols, rows)
      log('PTY resize', { ptyId: id, cols, rows })
      res.json({ success: true })
    } catch (error) {
      log('PTY resize error', { error: String(error) })
      res.status(500).json({ error: String(error) })
    }
  })

  // Kill PTY
  app.delete('/api/pty/:id', (req: Request, res: Response) => {
    try {
      const { id } = req.params

      const ptyManager = getPtyManager()
      if (!ptyManager) {
        return res.status(500).json({ error: 'PTY manager not available' })
      }

      if (!ptyManager.getProcess(id)) {
        return res.status(404).json({ error: 'PTY not found' })
      }

      ptyManager.kill(id)
      getLocalPtys().delete(id)

      // Close any WebSocket streams for this PTY
      const streams = getPtyStreams().get(id)
      if (streams) {
        streams.forEach(ws => {
          if (ws.readyState === WebSocket.OPEN) {
            ws.close(1000, 'PTY killed')
          }
        })
        getPtyStreams().delete(id)
      }

      log('PTY killed', { ptyId: id })
      res.json({ success: true })
    } catch (error) {
      log('PTY kill error', { error: String(error) })
      res.status(500).json({ error: String(error) })
    }
  })
}

/**
 * Mobile Server - Exposes IPC handlers as HTTP/WebSocket endpoints
 * for mobile app to connect to the desktop host
 */

import express, { Express, Request, Response } from 'express'
import { WebSocketServer, WebSocket } from 'ws'
import { createServer as createHttpServer, Server as HttpServer } from 'http'
import { createServer as createHttpsServer, Server as HttpsServer } from 'https'
import {
  getClientIp,
  getOrCreateFingerprint,
  getFormattedFingerprint,
  getCertificateFingerprint,
  getFormattedCertFingerprint,
  getTlsOptions,
  createNonce,
  verifyNonce,
  startNonceCleanup,
  stopNonceCleanup,
  recordFailedAuth,
  clearRateLimit,
  cleanupEndpointRateLimits
} from '../mobile-security'

import { MobileServerConfig, LocalPty, PendingFile, DEFAULT_PORT } from './types'
import { loadOrCreateToken, regenerateToken as regenerateTokenFn, saveToken } from './token-manager'
import { log, getRendererPath, getLocalIPs, getTailscaleHostname } from './utils'
import {
  setupCorsMiddleware,
  setupStaticMiddleware,
  setupJsonMiddleware,
  setupRateLimitMiddleware,
  setupAuthMiddleware,
  setupIpAccessMiddleware,
  setupEndpointRateLimitMiddleware
} from './middleware'
import {
  setupTerminalRoutes,
  setupWorkspaceRoutes,
  setupBeadsRoutes,
  setupFilesRoutes,
  setupPtyRoutes,
  setupTtsRoutes
} from './routes/index'
import {
  setupWebSocket,
  broadcastTerminalData as wsBroadcastTerminalData,
  broadcastPtyData as wsBroadcastPtyData,
  broadcastPtyExit as wsBroadcastPtyExit
} from './websocket-manager'
import {
  sendFileToMobile as filePushSendFile,
  getPendingFilesList,
  removePendingFile as filePushRemovePendingFile,
  cleanupExpiredFiles
} from './file-push'

export class MobileServer {
  private app: Express
  private server: HttpServer | HttpsServer | null = null
  private wss: WebSocketServer | null = null
  private token: string
  private port: number
  private terminalSubscriptions: Map<string, Set<WebSocket>> = new Map()
  private ptyStreams: Map<string, Set<WebSocket>> = new Map()
  private ptyDataBuffer: Map<string, string[]> = new Map()

  private ptyManager: any = null
  private sessionStore: any = null
  private voiceManager: any = null

  private localPtys: Map<string, LocalPty> = new Map()
  private pendingFiles: Map<string, PendingFile> = new Map()
  private connectedClients: Set<WebSocket> = new Set()

  private rendererPath: string
  private rateLimitCleanupInterval: ReturnType<typeof setInterval> | null = null
  private useTls: boolean = false // TODO: Enable once mobile app has cert pinning
  private certFingerprint: string = ''

  constructor(config: MobileServerConfig = {}) {
    this.port = config.port || DEFAULT_PORT
    this.token = loadOrCreateToken()
    this.rendererPath = getRendererPath()
    this.app = express()
    this.setupMiddleware()
    this.setupRoutes()
  }

  private setupMiddleware(): void {
    setupCorsMiddleware(this.app)
    setupStaticMiddleware(this.app, this.rendererPath)
    setupJsonMiddleware(this.app)
    setupRateLimitMiddleware(this.app)
    setupAuthMiddleware(this.app, () => this.token)
    setupIpAccessMiddleware(this.app)
    setupEndpointRateLimitMiddleware(this.app)
  }

  private setupRoutes(): void {
    // Health check (unauthenticated)
    this.app.get('/health', (req: Request, res: Response) => {
      log('Health check', { clientIp: getClientIp(req) })
      res.json({ status: 'ok', version: '2.0.0' })
    })

    // WebSocket test
    this.app.get('/ws-test', (req: Request, res: Response) => {
      const token = req.query.token as string
      log('WS test request', { providedToken: token?.slice(0, 8), expectedToken: this.token.slice(0, 8), clientIp: getClientIp(req) })
      if (token === this.token) {
        res.json({ ok: true, message: 'Token valid, WebSocket should work' })
      } else {
        res.status(403).json({ ok: false, message: 'Invalid token' })
      }
    })

    // Connection info for QR code (unauthenticated)
    this.app.get('/connect', (_req: Request, res: Response) => {
      const ips = getLocalIPs()
      res.json({
        port: this.port,
        ips,
        fingerprint: getFormattedFingerprint(),
        certFingerprint: this.certFingerprint,
        secure: this.useTls
      })
    })

    // Verify handshake nonce (unauthenticated)
    this.app.post('/verify-handshake', (req: Request, res: Response) => {
      const { nonce } = req.body
      log('Verify handshake request', { nonce: nonce?.slice(0, 8), clientIp: getClientIp(req) })

      if (!nonce || typeof nonce !== 'string') {
        return res.status(400).json({ error: 'Missing nonce' })
      }

      const valid = verifyNonce(nonce)

      if (!valid) {
        const clientIp = getClientIp(req)
        recordFailedAuth(clientIp)
        return res.status(403).json({
          valid: false,
          error: 'Invalid or expired nonce'
        })
      }

      res.json({
        valid: true,
        fingerprint: getOrCreateFingerprint(),
        certFingerprint: this.certFingerprint,
        secure: this.useTls
      })
    })

    // Set up route modules
    setupTerminalRoutes(
      this.app,
      () => this.ptyManager,
      () => this.terminalSubscriptions,
      (ptyId, data) => this.broadcastTerminalData(ptyId, data)
    )

    setupWorkspaceRoutes(this.app, () => this.sessionStore)

    setupBeadsRoutes(this.app)

    setupFilesRoutes(
      this.app,
      () => this.pendingFiles,
      (filePath, message) => this.sendFileToMobile(filePath, message),
      (fileId) => this.removePendingFile(fileId),
      () => this.connectedClients.size
    )

    setupPtyRoutes(
      this.app,
      () => this.ptyManager,
      () => this.localPtys,
      () => this.ptyStreams,
      () => this.ptyDataBuffer,
      (ptyId, data) => this.broadcastPtyData(ptyId, data),
      (ptyId, code) => this.broadcastPtyExit(ptyId, code)
    )

    setupTtsRoutes(this.app, () => this.voiceManager)
  }

  private setupWebSocket(): void {
    if (!this.server) return

    this.wss = setupWebSocket(this.server, {
      getToken: () => this.token,
      getPtyManager: () => this.ptyManager,
      getPort: () => this.port,
      getTerminalSubscriptions: () => this.terminalSubscriptions,
      getPtyStreams: () => this.ptyStreams,
      getPtyDataBuffer: () => this.ptyDataBuffer,
      getConnectedClients: () => this.connectedClients,
      getPendingFiles: () => this.pendingFiles
    })
  }

  private broadcastTerminalData(ptyId: string, data: string): void {
    wsBroadcastTerminalData(ptyId, data, this.terminalSubscriptions)
  }

  private broadcastPtyData(ptyId: string, data: string): void {
    wsBroadcastPtyData(ptyId, data, this.ptyStreams, this.ptyDataBuffer)
  }

  private broadcastPtyExit(ptyId: string, code: number): void {
    wsBroadcastPtyExit(ptyId, code, this.ptyStreams, this.terminalSubscriptions)
  }

  // Service handlers
  setPtyManager(manager: any): void {
    this.ptyManager = manager
  }

  setSessionStore(store: any): void {
    this.sessionStore = store
  }

  setVoiceManager(manager: any): void {
    this.voiceManager = manager
  }

  // Token management
  regenerateToken(): string {
    this.token = regenerateTokenFn()
    return this.token
  }

  // Connection info for QR code
  getConnectionInfo(): {
    url: string
    token: string
    port: number
    ips: string[]
    fingerprint: string
    formattedFingerprint: string
    certFingerprint: string
    secure: boolean
    nonce: string
    nonceExpires: number
    qrData: string
  } {
    const ips = getLocalIPs()
    const primaryIp = ips[0] || 'localhost'
    const fingerprint = getOrCreateFingerprint()
    const { nonce, expiresAt } = createNonce()

    const tailscaleHostname = getTailscaleHostname()
    const allHosts = tailscaleHostname ? [...ips, tailscaleHostname] : ips

    // QR version 3: adds TLS certificate pinning
    // - certFingerprint: SHA256 of server's TLS certificate (for pinning)
    // - secure: true means use HTTPS/WSS
    const qrPayload = {
      type: 'claude-terminal',
      version: 3,
      host: primaryIp,
      hosts: allHosts,
      port: this.port,
      token: this.token,
      fingerprint, // Legacy app-level fingerprint
      certFingerprint: this.certFingerprint, // TLS certificate fingerprint for pinning
      secure: this.useTls,
      nonce,
      nonceExpires: expiresAt
    }

    const protocol = this.useTls ? 'https' : 'http'
    return {
      url: `claude-terminal://${primaryIp}:${this.port}?token=${this.token}`,
      token: this.token,
      port: this.port,
      ips,
      fingerprint,
      formattedFingerprint: getFormattedFingerprint(),
      certFingerprint: this.certFingerprint,
      secure: this.useTls,
      nonce,
      nonceExpires: expiresAt,
      qrData: JSON.stringify(qrPayload)
    }
  }

  generateNonce(): { nonce: string; expiresAt: number } {
    return createNonce()
  }

  // File push methods
  sendFileToMobile(filePath: string, message?: string): { success: boolean; fileId?: string; error?: string } {
    return filePushSendFile(filePath, message, this.pendingFiles, this.connectedClients)
  }

  getPendingFiles(): PendingFile[] {
    return getPendingFilesList(this.pendingFiles)
  }

  removePendingFile(fileId: string): boolean {
    return filePushRemovePendingFile(fileId, this.pendingFiles)
  }

  getConnectedClientCount(): number {
    return this.connectedClients.size
  }

  async start(): Promise<void> {
    try {
      // Get TLS certificate (generates on first run)
      if (this.useTls) {
        log('Initializing TLS certificate...')
        const tlsOptions = await getTlsOptions()
        this.certFingerprint = await getCertificateFingerprint()
        this.server = createHttpsServer(tlsOptions, this.app)
        log(`TLS enabled, cert fingerprint: ${this.certFingerprint.slice(0, 16)}...`)
      } else {
        this.server = createHttpServer(this.app)
        log('TLS disabled, using HTTP')
      }

      this.setupWebSocket()
      startNonceCleanup()

      this.rateLimitCleanupInterval = setInterval(() => {
        cleanupEndpointRateLimits()
      }, 2 * 60 * 1000)

      return new Promise((resolve, reject) => {
        this.server!.listen(this.port, '0.0.0.0', () => {
          const protocol = this.useTls ? 'HTTPS' : 'HTTP'
          log(`Started ${protocol} server on port ${this.port}`)
          log(`Token: ${this.token.slice(0, 8)}...`)
          if (this.useTls) {
            log(`Cert fingerprint: ${this.certFingerprint.slice(0, 32)}...`)
          }
          resolve()
        })

        this.server!.on('error', (err: NodeJS.ErrnoException) => {
          if (err.code === 'EADDRINUSE') {
            log(`Port ${this.port} in use, trying ${this.port + 1}`)
            this.port++
            this.server?.close()
            this.start().then(resolve).catch(reject)
          } else {
            log('Server error', { error: String(err) })
            reject(err)
          }
        })
      })
    } catch (error) {
      log('Failed to start server', { error: String(error) })
      throw error
    }
  }

  stop(): void {
    stopNonceCleanup()

    if (this.rateLimitCleanupInterval) {
      clearInterval(this.rateLimitCleanupInterval)
      this.rateLimitCleanupInterval = null
    }

    if (this.wss) {
      this.wss.close()
      this.wss = null
    }
    if (this.server) {
      this.server.close()
      this.server = null
    }
    log('Stopped')
  }

  isRunning(): boolean {
    return this.server !== null && this.server.listening
  }
}

// Re-export types
export * from './types'

/**
 * Beads Adapter
 *
 * Wraps existing window.electronAPI.beads* calls into the TaskAdapter interface.
 * This is a thin shim — all logic stays in the existing IPC handlers.
 */

import type {
  TaskAdapter,
  BackendStatus,
  UnifiedTask,
  CreateTaskParams,
  UpdateTaskParams,
  TaskStatus
} from './types.js'

function normalizeStatus(status: string): TaskStatus {
  switch (status) {
    case 'in_progress': return 'in_progress'
    case 'closed': return 'closed'
    default: return 'open'
  }
}

function toUnified(raw: Record<string, unknown>): UnifiedTask {
  return {
    id: String(raw.id ?? ''),
    title: String(raw.title ?? ''),
    status: normalizeStatus(String(raw.status ?? 'open')),
    priority: typeof raw.priority === 'number' ? raw.priority : undefined,
    type: typeof raw.issue_type === 'string' ? raw.issue_type : undefined,
    description: typeof raw.description === 'string' ? raw.description : undefined,
    created_at: typeof raw.created_at === 'string' ? raw.created_at : typeof raw.created === 'string' ? raw.created : undefined,
    updated_at: typeof raw.updated_at === 'string' ? raw.updated_at : undefined,
    _backend: 'beads'
  }
}

export class BeadsAdapter implements TaskAdapter {
  readonly kind = 'beads' as const

  async check(cwd: string): Promise<BackendStatus> {
    const status = await window.electronAPI?.beadsCheck(cwd)
    if (!status) {
      return { kind: 'beads', installed: false, initialized: false }
    }
    return {
      kind: 'beads',
      installed: status.installed,
      initialized: status.initialized
    }
  }

  async init(cwd: string): Promise<{ success: boolean; error?: string }> {
    const result = await window.electronAPI?.beadsInit(cwd)
    return { success: !!result?.success, error: result?.error }
  }

  async list(cwd: string): Promise<UnifiedTask[]> {
    const result = await window.electronAPI?.beadsList(cwd)
    if (!result?.success || !result.tasks) return []
    return (result.tasks as Record<string, unknown>[]).map(toUnified)
  }

  async show(cwd: string, taskId: string): Promise<UnifiedTask | null> {
    const result = await window.electronAPI?.beadsShow(cwd, taskId)
    if (!result?.success || !result.task) return null
    return toUnified(result.task as Record<string, unknown>)
  }

  async create(cwd: string, params: CreateTaskParams): Promise<{ success: boolean; error?: string }> {
    const result = await window.electronAPI?.beadsCreate(
      cwd,
      params.title,
      params.description,
      params.priority,
      params.type,
      params.tags
    )
    return { success: !!result?.success, error: result?.error }
  }

  async start(cwd: string, taskId: string): Promise<{ success: boolean; error?: string }> {
    const result = await window.electronAPI?.beadsStart(cwd, taskId)
    return { success: !!result?.success, error: result?.error }
  }

  async complete(cwd: string, taskId: string): Promise<{ success: boolean; error?: string }> {
    const result = await window.electronAPI?.beadsComplete(cwd, taskId)
    return { success: !!result?.success, error: result?.error }
  }

  async delete(cwd: string, taskId: string): Promise<{ success: boolean; error?: string }> {
    const result = await window.electronAPI?.beadsDelete(cwd, taskId)
    return { success: !!result?.success, error: result?.error }
  }

  async update(cwd: string, taskId: string, params: UpdateTaskParams): Promise<{ success: boolean; error?: string }> {
    const result = await window.electronAPI?.beadsUpdate(
      cwd,
      taskId,
      params.status,
      params.title,
      params.description,
      params.priority
    )
    return { success: !!result?.success, error: result?.error }
  }

  async cycleStatus(cwd: string, taskId: string, currentStatus: TaskStatus): Promise<{ success: boolean; error?: string }> {
    let nextStatus: string
    switch (currentStatus) {
      case 'open': nextStatus = 'in_progress'; break
      case 'in_progress': nextStatus = 'closed'; break
      default: nextStatus = 'open'
    }
    return this.update(cwd, taskId, { status: nextStatus as TaskStatus })
  }

  watch(cwd: string): void {
    window.electronAPI?.beadsWatch(cwd)
  }

  unwatch(cwd: string): void {
    window.electronAPI?.beadsUnwatch(cwd)
  }

  onTasksChanged(callback: (data: { cwd: string }) => void): () => void {
    return window.electronAPI?.onBeadsTasksChanged(callback) ?? (() => {})
  }
}

